		["push", "origin", "HEAD:" + targetBranch],
		cwd,
	);

	if (pushCommand.exit_code !== 0) {
		return {
			ok: false,
			error: "Could not push the assigned branch.",
			commands: {
				commit_count: commitCountCommand,
				push: pushCommand,
			},
		};
	}

	const verifyCommand = await runCommand(
		"git",
		["ls-remote", "--heads", "origin", targetBranch],
		cwd,
	);

